import React, { useState, useEffect } from 'react';
import Editor from '@monaco-editor/react';
import { Play, CheckCircle, BookOpen, Code, Trophy, MessageCircle, Flame, ChevronRight, Star, Sun, Moon } from 'lucide-react';
import './App.css';

const LANGUAGES = [
  { id: 'python', name: 'Python', color: '#3776ab', icon: '🐍' },
  { id: 'javascript', name: 'JavaScript', color: '#f7df1e', icon: '⚡' },
  { id: 'html', name: 'HTML', color: '#e34c26', icon: '🌐' },
  { id: 'css', name: 'CSS', color: '#264de4', icon: '🎨' }
];

const LESSONS = {
  python: [
    {
      id: 1,
      title: 'Print Statement',
      content: 'In Python, we use print() to show output. Try printing "Hello, World!"',
      code: '# Write your code here\nprint("Hello, World!")',
      expected: 'Hello, World!',
      hint: 'Use print() with your message inside quotes',
      difficulty: 'beginner',
      quiz: [
        { question: 'What function is used to output text in Python?', options: ['echo()', 'print()', 'console.log()', 'output()'], correct: 1 },
        { question: 'What will print("Hi") display?', options: ['print("Hi")', 'Hi', '"Hi"', 'Nothing'], correct: 1 }
      ]
    },
    {
      id: 2,
      title: 'Variables',
      content: 'Variables store data. Create a variable named name with your name and print it.',
      code: '# Create a variable and print it\nname = "Your Name"\nprint(name)',
      expected: 'Your Name',
      hint: 'name = "John" then print(name)',
      difficulty: 'beginner',
      quiz: [
        { question: 'How do you create a variable in Python?', options: ['var name = "John"', 'let name = "John"', 'name = "John"', 'string name = "John"'], correct: 2 },
        { question: 'What will x = 10 store?', options: ['Text', 'Number 10', 'Nothing', 'Error'], correct: 1 }
      ]
    },
    {
      id: 3,
      title: 'Simple Math',
      content: 'Python can do math. Calculate 10 + 5 and print the result.',
      code: '# Calculate and print\nresult = 10 + 5\nprint(result)',
      expected: '15',
      hint: 'Use +, -, *, / for math operations',
      difficulty: 'beginner',
      quiz: [
        { question: 'What is 15 // 4 in Python?', options: ['3.75', '3', '4', '3.0'], correct: 1 },
        { question: 'Which operator is used for multiplication?', options: ['x', '*', '×', 'mult()'], correct: 1 }
      ]
    }
  ],
  javascript: [
    {
      id: 1,
      title: 'Console Log',
      content: 'JavaScript uses console.log() to display output. Print "Hello JS!"',
      code: '// Write your code here\nconsole.log("Hello JS!");',
      expected: 'Hello JS!',
      hint: 'Use console.log() with your message',
      difficulty: 'beginner',
      quiz: [
        { question: 'Where does console.log() output appear?', options: ['Popup alert', 'Console/Terminal', 'Web page', 'File'], correct: 1 },
        { question: 'What symbol ends a JavaScript statement?', options: ['.', ';', ':', '!'], correct: 1 }
      ]
    },
    {
      id: 2,
      title: 'Variables with let',
      content: 'Use let to create variables. Make a variable age = 20 and log it.',
      code: '// Create variable and log\nlet age = 20;\nconsole.log(age);',
      expected: '20',
      hint: 'let variableName = value;',
      difficulty: 'beginner',
      quiz: [
        { question: 'Which keyword declares a variable in modern JS?', options: ['var', 'let', 'const', 'All of these'], correct: 3 },
        { question: 'What is the value of: let x = 5 + 3?', options: ['53', '8', 'Error', 'undefined'], correct: 1 }
      ]
    }
  ],
  html: [
    {
      id: 1,
      title: 'Basic Structure',
      content: 'HTML uses tags. Create a heading with h1 tag.',
      code: '<!-- Write HTML here -->\n<h1>My First Page</h1>',
      expected: 'My First Page',
      hint: '<h1>Your text</h1>',
      difficulty: 'beginner',
      quiz: [
        { question: 'What does HTML stand for?', options: ['Hyper Text Markup Language', 'High Tech Modern Language', 'Hyper Transfer Mark Language', 'Home Tool Markup Language'], correct: 0 },
        { question: 'Which tag creates the largest heading?', options: ['<head>', '<h6>', '<h1>', '<header>'], correct: 2 }
      ]
    },
    {
      id: 2,
      title: 'Paragraph Tag',
      content: 'Use p tag for paragraphs. Create a paragraph saying "I love coding".',
      code: '<!-- Add a paragraph -->\n<p>I love coding</p>',
      expected: 'I love coding',
      hint: '<p>Your paragraph text</p>',
      difficulty: 'beginner',
      quiz: [
        { question: 'Which tag creates a paragraph?', options: ['<para>', '<p>', '<paragraph>', '<text>'], correct: 1 },
        { question: 'Do HTML tags need to be closed?', options: ['Always', 'Never', 'Mostly yes', 'Only for images'], correct: 2 }
      ]
    }
  ],
  css: [
    {
      id: 1,
      title: 'Change Color',
      content: 'CSS styles HTML. Make text red using color property.',
      code: '/* Style the text */\nh1 {\n  color: red;\n}',
      expected: 'color: red',
      hint: 'selector { property: value; }',
      difficulty: 'beginner',
      quiz: [
        { question: 'What does CSS stand for?', options: ['Computer Style Sheets', 'Cascading Style Sheets', 'Creative Style System', 'Color Style Sheets'], correct: 1 },
        { question: 'Which property changes text color?', options: ['text-color', 'font-color', 'color', 'text-style'], correct: 2 }
      ]
    },
    {
      id: 2,
      title: 'Background Color',
      content: 'Change background color. Make body background yellow.',
      code: '/* Change background */\nbody {\n  background-color: yellow;\n}',
      expected: 'background-color: yellow',
      hint: 'background-color: colorname;',
      difficulty: 'beginner',
      quiz: [
        { question: 'Which property sets background color?', options: ['bg-color', 'background-color', 'color-background', 'bgcolor'], correct: 1 },
        { question: 'Where do you write CSS rules?', options: ['Inside HTML tags', 'Between <style> tags or .css file', 'In JavaScript', 'In the URL'], correct: 1 }
      ]
    }
  ]
};

function App() {
  const [selectedLang, setSelectedLang] = useState('python');
  const [currentLesson, setCurrentLesson] = useState(0);
  const [code, setCode] = useState('');
  const [output, setOutput] = useState('');
  const [streak, setStreak] = useState(12);
  const [completed, setCompleted] = useState([]);
  const [xp, setXp] = useState(150);
  const [showHint, setShowHint] = useState(false);
  const [doubts, setDoubts] = useState([]);
  const [doubtMsg, setDoubtMsg] = useState('');
  const [theme, setTheme] = useState('dark');
  const [showQuiz, setShowQuiz] = useState(false);
  const [quizAnswers, setQuizAnswers] = useState({});
  const [quizScore, setQuizScore] = useState(0);
  const [quizSubmitted, setQuizSubmitted] = useState(false);
  const [currentPage, setCurrentPage] = useState('learn');

  const lesson = LESSONS[selectedLang][currentLesson];

  const toggleTheme = () => {
    setTheme(theme === 'dark' ? 'light' : 'dark');
  };

  useEffect(() => {
    setCode(LESSONS[selectedLang][currentLesson].code);
    setOutput('');
    setShowHint(false);
  }, [selectedLang, currentLesson]);

  const runCode = () => {
    const lesson = LESSONS[selectedLang][currentLesson];
    let result = '';

    if (selectedLang === 'python') {
      if (code.includes('print(')) {
        const match = code.match(/print\(["\'](.+?)["\']\)/);
        if (match) result = match[1];
        else {
          const varMatch = code.match(/print\((\w+)\)/);
          if (varMatch) {
            const varName = varMatch[1];
            const varLine = code.match(new RegExp(varName + '\\s*=\\s*["\'](.+?)["\']'));
            if (varLine) result = varLine[1];
          }
          const numMatch = code.match(/print\((\d+\s*[+\-*/]\s*\d+)\)/);
          if (numMatch) {
            try {
              result = eval(numMatch[1]).toString();
            } catch (e) {
              result = 'Error';
            }
          }
        }
      }
    } else if (selectedLang === 'javascript') {
      if (code.includes('console.log(')) {
        const match = code.match(/console\.log\(["\'](.+?)["\']\)/);
        if (match) result = match[1];
        else {
          const varMatch = code.match(/console\.log\((\w+)\)/);
          if (varMatch) {
            const varName = varMatch[1];
            const varLine = code.match(new RegExp(`let\\s+${varName}\\s*=\\s*(\\d+)`));
            if (varLine) result = varLine[1];
          }
        }
      }
    } else if (selectedLang === 'html') {
      const match = code.match(/<h1>(.+?)<\/h1>/) || code.match(/<p>(.+?)<\/p>/);
      if (match) result = match[1];
    } else if (selectedLang === 'css') {
      if (code.includes('color: red')) result = 'color: red';
      else if (code.includes('background-color: yellow')) result = 'background-color: yellow';
    }

    setOutput(result);

    if (result && (lesson.expected === result || result.includes(lesson.expected) || lesson.expected.includes(result))) {
      if (!completed.includes(`${selectedLang}-${currentLesson}`)) {
        setCompleted([...completed, `${selectedLang}-${currentLesson}`]);
        setXp(xp + 10);
      }
    }
  };

  const nextLesson = () => {
    if (currentLesson < LESSONS[selectedLang].length - 1) {
      setCurrentLesson(currentLesson + 1);
    }
  };

  const prevLesson = () => {
    if (currentLesson > 0) {
      setCurrentLesson(currentLesson - 1);
    }
  };

  const sendDoubt = () => {
    if (doubtMsg.trim()) {
      setDoubts([...doubts, { user: 'You', msg: doubtMsg, time: new Date().toLocaleTimeString() }]);
      setDoubtMsg('');
    }
  };

  const selectQuizAnswer = (questionIndex, optionIndex) => {
    setQuizAnswers({ ...quizAnswers, [questionIndex]: optionIndex });
  };

  const submitQuiz = () => {
    const currentLessonData = LESSONS[selectedLang][currentLesson];
    let score = 0;
    currentLessonData.quiz.forEach((q, idx) => {
      if (quizAnswers[idx] === q.correct) score++;
    });
    setQuizScore(score);
    setQuizSubmitted(true);
    if (score === currentLessonData.quiz.length) {
      setXp(xp + 20);
      if (!completed.includes(`${selectedLang}-${currentLesson}-quiz`)) {
        setCompleted([...completed, `${selectedLang}-${currentLesson}-quiz`]);
      }
    }
  };

  const closeQuiz = () => {
    setShowQuiz(false);
    setQuizAnswers({});
    setQuizSubmitted(false);
  };

  const openQuizPage = () => {
    setCurrentPage('quiz');
    setQuizAnswers({});
    setQuizSubmitted(false);
  };

  const progress = ((completed.filter(c => c.startsWith(selectedLang)).length / LESSONS[selectedLang].length) * 100).toFixed(0);

  return (
    <div className={`min-h-screen flex ${theme === 'dark' ? 'bg-gray-900 text-white' : 'bg-gray-50 text-gray-900'}`}>
      {/* Left Sidebar */}
      <div className={`w-64 ${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-r`}>
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <div className="bg-gradient-to-r from-blue-500 to-purple-600 p-2 rounded-lg">
              <Code size={24} className="text-white" />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
              CodeLearn
            </h1>
          </div>

          <nav className="space-y-2">
            {[
              { id: 'learn', icon: <BookOpen size={20} />, label: 'Learn' },
              { id: 'quiz', icon: <Trophy size={20} />, label: 'Quiz' },
              { id: 'journey', icon: <Flame size={20} />, label: 'Journey' },
              { id: 'leaderboard', icon: <Star size={20} />, label: 'Leaderboard' },
            ].map(item => (
              <button
                key={item.id}
                onClick={() => setCurrentPage(item.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                  currentPage === item.id
                    ? `${theme === 'dark' ? 'bg-gray-700' : 'bg-blue-50 text-blue-600'} font-medium`
                    : `${theme === 'dark' ? 'hover:bg-gray-700' : 'hover:bg-gray-100'}`
                }`}
              >
                {item.icon}
                <span>{item.label}</span>
              </button>
            ))}

            <button
              onClick={() => setCurrentPage('profile')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                currentPage === 'profile'
                  ? `${theme === 'dark' ? 'bg-gray-700' : 'bg-blue-50 text-blue-600'} font-medium`
                  : `${theme === 'dark' ? 'hover:bg-gray-700' : 'hover:bg-gray-100'}`
              }`}
            >
              <div className="w-8 h-8 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center text-white font-bold text-sm">
                U
              </div>
              <span>Profile</span>
            </button>
          </nav>
        </div>

        <div className={`p-6 border-t ${theme === 'dark' ? 'border-gray-700' : 'border-gray-200'}`}>
          <div className="flex items-center gap-2 mb-3">
            <Flame size={20} className="text-orange-500" />
            <span className="font-bold">{streak} day streak</span>
          </div>
          <div className="flex items-center gap-2">
            <Trophy size={20} className="text-yellow-500" />
            <span className="font-bold">{xp} XP</span>
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1">
        {/* Header */}
        <header className={`${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-b px-6 py-4`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-bold capitalize">{currentPage}</h2>
            <button
              onClick={toggleTheme}
              className={`flex items-center gap-2 px-4 py-2 rounded-full transition-colors ${
                theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600 text-yellow-400' : 'bg-gray-200 hover:bg-gray-300 text-orange-500'
              }`}
            >
              {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
              <span className="font-medium">{theme === 'dark' ? 'Light' : 'Dark'}</span>
            </button>
          </div>
        </header>

        {/* Learn Page */}
        {currentPage === 'learn' && (
          <>
            <div className={`${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-b px-6 py-3`}>
              <div className="max-w-7xl mx-auto flex gap-3">
                {LANGUAGES.map(lang => (
                  <button
                    key={lang.id}
                    onClick={() => { setSelectedLang(lang.id); setCurrentLesson(0); }}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
                      selectedLang === lang.id
                        ? `${theme === 'dark' ? 'bg-gray-700 text-white' : 'bg-blue-100 text-blue-900'} ring-2 ring-blue-500`
                        : `${theme === 'dark' ? 'bg-gray-800 text-gray-400 hover:bg-gray-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`
                    }`}
                  >
                    <span>{lang.icon}</span>
                    <span className="font-medium">{lang.name}</span>
                    {completed.filter(c => c.startsWith(lang.id)).length === LESSONS[lang.id].length && (
                      <CheckCircle size={16} className="text-green-500" />
                    )}
                  </button>
                ))}
              </div>
            </div>

            <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Left Column */}
              <div className="space-y-4">
                <div className={`${theme === 'dark' ? 'bg-gray-800' : 'bg-white shadow-md'} rounded-xl p-4`}>
                  <div className="flex items-center justify-between mb-2">
                    <span className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-600'}`}>Course Progress</span>
                    <span className="text-sm font-bold text-blue-400">{progress}%</span>
                  </div>
